import React, { useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';

const WordCloud = () => {
  const [words, setWords] = useState([]);

  useEffect(() => {
    const fetchWords = async () => {
      const { data } = await supabase.from('proposals').select('content').limit(30);
      if (data) {
        const text = data.map(p => p.content).join(' ');
        const common = ['le', 'la', 'les', 'de', 'des', 'et', 'est', 'sont', 'pour', 'dans', 'avec', 'que', 'qui', 'une', 'pas', 'plus'];
        const freq = {};
        text.toLowerCase().split(/\s+/).forEach(w => {
          if (w.length > 3 && !common.includes(w)) freq[w] = (freq[w] || 0) + 1;
        });
        const sorted = Object.entries(freq).sort((a,b) => b[1] - a[1]).slice(0, 20);
        setWords(sorted.map(([w, c]) => ({ word: w, size: 16 + Math.min(c * 2, 48) })));
      } else {
        setWords([
          { word: "Élections", size: 36 }, { word: "Justice", size: 32 }, { word: "Mandat", size: 28 },
          { word: "Constitution", size: 40 }, { word: "Décentralisation", size: 26 }, { word: "Gouvernance", size: 30 }
        ]);
      }
    };
    fetchWords();
  }, []);

  return (
    <div className="word-cloud">
      <h3>Nuage de mots-clés</h3>
      <p>Analyse sémantique des contributions citoyennes</p>
      <div className="cloud">
        {words.map((w, i) => (
          <span key={i} className="cloud-word" style={{ fontSize: w.size }}>{w.word}</span>
        ))}
      </div>
    </div>
  );
};

export default WordCloud;
